// Guard clauses — flat, readable preconditions

fn divide(a, b) {
  guard b != 0 else { return "Cannot divide by zero" }
  return a / b
}

fn greetUser(user) {
  guard user != null else { return "No user provided" }
  guard user.name != null else { return "User has no name" }
  return "Hello, ${user.name}!"
}

print divide(10, 3)
print divide(10, 0)
print greetUser({name: "Alice"})
print greetUser(null)

// Contracts — type + guard + is

type HasName = {name: string}
type HasEmail = {email: string}
type Circle = {radius: number}
type Rectangle = {width: number, height: number}

// Intersection: must satisfy ALL contracts
fn profile(user) {
  guard user is HasName, HasEmail else { return "missing fields" }
  return "${user.name} <${user.email}>"
}

print profile({name: "Alice", email: "a@test.com"})
print profile({name: "Bob"})

// Union: must satisfy ANY contract
fn area(shape) {
  guard shape in Circle, Rectangle else { return "unknown" }
  return match shape {
    is Circle => 3.14 * shape.radius * shape.radius
    is Rectangle => shape.width * shape.height
  }
}

print "circle: ${area({radius: 5})}"
print "rect: ${area({width: 4, height: 6})}"
print "other: ${area({sides: 3})}"

// Enums with exhaustive match expressions

enum Color { Red, Green, Blue }
enum Shape { Circle, Square, Triangle }

fn colorName(c) {
  return match c {
    Color.Red => "red"
    Color.Green => "green"
    Color.Blue => "blue"
  }
}

fn shapeInfo(shape, color) {
  return "a ${colorName(color)} ${match shape {
    Shape.Circle => "circle"
    Shape.Square => "square"
    Shape.Triangle => "triangle"
  }}"
}

print shapeInfo(Shape.Circle, Color.Red)
print shapeInfo(Shape.Triangle, Color.Blue)

