// Return types — declare what a function returns

type Success = {ok: boolean, data: any}
type Failure = {ok: boolean, error: string}

// Union return: one of these shapes
fn divide(a, b) in Success, Failure {
  guard b != 0 else { return {ok: false, error: "division by zero"} }
  return {ok: true, data: a / b}
}

fn showResult(r) {
  return match r {
    is Success => "result: ${r.data}"
    is Failure => "error: ${r.error}"
    _ => "unknown"
  }
}

print showResult(divide(10, 3))
print showResult(divide(10, 0))

// Intersection return: has ALL shapes
type HasName = {name: string}
type HasEmail = {email: string}

fn createContact(n, e) is HasName, HasEmail {
  return {name: n, email: e}
}

dec c = createContact("Alice", "a@test.com")
print "${c.name} <${c.email}>"

// Regex — three ways to use patterns

// 1. Match operator (~) extracts matches
dec input = "Hello, World! 123"
dec greeting = input ~ /Hello/
print "Found: ${greeting}"

// 2. Match with capture groups
dec name = "Hello, Alice!" ~ /Hello, (\w+)!/ => {
  return "Welcome, ${$match[1]}!"
}
print name

// 3. Regex patterns in match expressions
fn classify(line) {
  return match line {
    /^ERROR/ => "critical"
    /^WARN/ => "warning"
    /^INFO/ => "info"
    _ => "unknown"
  }
}

print classify("ERROR: disk full")
print classify("WARN: low memory")
print classify("INFO: started")
print classify("something else")
